from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a comics character (or related entities)
    into a single fluent English sentence.
    """
    if not triples:
        return ""

    parts: list[str] = []
    for t in triples:
        s, p, o = t.subject, t.predicate, t.object

        # Helper to ensure quoted objects stay quoted
        def fmt_obj(obj: str) -> str:
            return obj if (obj.startswith('"') and obj.endswith('"')) else obj

        if p == "alternativeName":
            parts.append(f"{s} is also known as {fmt_obj(o)}")
        elif p == "creator":
            parts.append(f"{s} was created by {o}")
        elif p == "fullName":
            parts.append(f"{s}'s full name is {o}")
        elif p == "foundedBy":
            parts.append(f"{s} was founded by {o}")
        elif p == "keyPerson":
            parts.append(f"{s} has a key person: {o}")
        elif p == "city":
            parts.append(f"{s} is based in {o}")
        elif p == "product":
            parts.append(f"{s} produces {o}")
        elif p == "lastAired":
            parts.append(f"The final episode of {s} aired on {o}")
        elif p == "starring":
            parts.append(f"{s} stars {o}")
        elif p == "firstAppearanceInFilm":
            parts.append(f"{s} first appeared in the film {o}")
        elif p == "voice":
            parts.append(f"{s} is voiced by {o}")
        elif p == "distributor":
            parts.append(f"The film {s} was distributed by {o}")
        elif p == "birthPlace":
            parts.append(f"{s} was born in {o}")
        elif p == "nationality":
            parts.append(f"{s} is {o}")
        elif p == "award":
            parts.append(f"{s} received the {o}")
        elif p == "broadcastedBy":
            parts.append(f"{s} was broadcast by {o}")
        elif p == "firstAired":
            parts.append(f"{s} first aired on {o}")
        elif p == "series":
            parts.append(f"{s} is part of the series {o}")
        elif p == "child":
            parts.append(f"{s} has a child named {o}")
        else:
            parts.append(f"{s} {p} {o}")

    # Combine parts into one sentence
    if len(parts) == 1:
        sentence = parts[0] + "."
    else:
        sentence = ", ".join(parts[:-1]) + ", and " + parts[-1] + "."
    return sentence

